/**
 * TypeScript interfaces for the Pipeline Config Editor.
 * Covers all 26 keys generated by Tool 90 (Pipeline Config Generator).
 */

// ── Nested value types ──────────────────────────────────────────

export interface JoinKeyEntry {
  alias: string;
  join_key: string;
  dim_columns: string[];
  dim_key?: string;
}

export interface FactJoinEntry {
  join_expr: string;
  dim_aliases: string[];
  [key: string]: unknown;
}

export interface EnrichmentJoinEntry {
  name: string;
  source: string;
  join_on: string;
  dim_columns: string[];
}

export interface SwitchDecompositionEntry {
  name: string;
  raw_expr: string;
  comment: string;
}

export interface MeasureResolutionEntry {
  base_expr: string;
  base_filters: string[];
}

export interface ManualOverrideEntry {
  sql_expr: string;
  comment: string;
  [key: string]: unknown;
}

export interface MappingOnlyTableEntry {
  source_table: string;
  dimensions: string[];
}

export interface ColumnMetadataEntry {
  data_type: string;
  is_hidden: boolean;
  format_string?: string;
  [key: string]: unknown;
}

// ── Full pipeline config (26 keys) ─────────────────────────────

export interface PipelineConfig {
  // JOIN CONFIGURATION (keys 1-4)
  join_key_map: Record<string, JoinKeyEntry>;
  fact_join_map: Record<string, FactJoinEntry>;
  enrichment_joins: Record<string, EnrichmentJoinEntry[]>;
  dim_alias_map: Record<string, string>;

  // MEASURE & SWITCH LOGIC (keys 5-11)
  switch_decompositions: Record<string, SwitchDecompositionEntry[]>;
  measure_resolutions: Record<string, MeasureResolutionEntry>;
  // How many other measures reference each measure (in-degree). Surfaced next to
  // TODO entries so reviewers prioritize high-impact gaps. Measure refs only.
  measure_usage?: Record<string, number>;
  filter_sets: Record<string, string[]>;
  manual_overrides: Record<string, ManualOverrideEntry>;
  budget_suffix: string | null;
  switch_join_alias: string | null;
  switch_join_col: string | null;

  // COLUMN & METADATA (keys 12-17)
  column_metadata: Record<string, ColumnMetadataEntry>;
  column_overrides: Record<string, unknown>;
  column_alias_map: Record<string, string>;
  comment_overrides: Record<string, string>;
  measure_metadata: Record<string, string>;
  dimension_metadata: Record<string, unknown>;

  // TIME/PERIOD DIMENSIONS (keys 18-19)
  period_dim_priority: string[];
  int_period_dims: string[];

  // FILTERING & PARAMETERS (keys 20-22)
  parameter_defaults: Record<string, string>;
  cwc_filter_column: string | null;
  percentage_multiplier_patterns: string[];

  // NAME NORMALIZATION (keys 23-25)
  name_prefixes_to_strip: string[];
  dimension_order: Record<string, string[]>;
  dimension_exclusions: Record<string, string[]>;

  // SPECIAL CASES (key 26)
  mapping_only_tables: Record<string, MappingOnlyTableEntry>;

  // Allow additional keys
  [key: string]: unknown;
}

// ── Key status tracking ─────────────────────────────────────────

export type ConfigKeyStatus = 'auto' | 'todo' | 'empty' | 'null';

export interface ConfigKeyInfo {
  key: string;
  status: ConfigKeyStatus;
  label: string;
  category: string;
  valueType: 'string' | 'string-nullable' | 'list' | 'dict' | 'dict-of-list' | 'dict-of-dict';
  entryCount: number;
  todoCount: number;
}

