// ── Helper: classify a key's value type ─────────────────────────

export function classifyValueType(
  key: string,
  value: unknown,
): ConfigKeyInfo['valueType'] {
  // Nullable strings
  const nullableStringKeys = new Set([
    'budget_suffix', 'switch_join_alias', 'switch_join_col', 'cwc_filter_column',
  ]);
  if (nullableStringKeys.has(key)) return 'string-nullable';

  // Lists
  const listKeys = new Set([
    'period_dim_priority', 'int_period_dims', 'percentage_multiplier_patterns',
    'name_prefixes_to_strip',
  ]);
  if (listKeys.has(key)) return 'list';

  // Dict-of-list (values are arrays)
  const dictOfListKeys = new Set([
    'enrichment_joins', 'switch_decompositions', 'filter_sets',
    'dimension_order', 'dimension_exclusions',
  ]);
  if (dictOfListKeys.has(key)) return 'dict-of-list';

  // Dict-of-dict
  if (value && typeof value === 'object' && !Array.isArray(value)) return 'dict-of-dict';

  // Fallback
  if (Array.isArray(value)) return 'list';
  return 'string';
}

// ── Helper: determine status of a key ───────────────────────────

export function getKeyStatus(value: unknown): ConfigKeyStatus {
  if (value === null || value === undefined) return 'null';

  const str = JSON.stringify(value);

  if (str.includes('TODO')) return 'todo';

  // Check emptiness
  if (typeof value === 'string' && value.trim() === '') return 'empty';
  if (Array.isArray(value) && value.length === 0) return 'empty';
  if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value as object).length === 0) return 'empty';

  return 'auto';
}

// Count TODO markers in a value
export function countTodos(value: unknown): number {
  if (value === null || value === undefined) return 0;
  const str = JSON.stringify(value);
  return (str.match(/TODO/g) || []).length;
}
